import{_ as a,o as r,c as t,a2 as o}from"./chunks/framework.DdLJaIXX.js";const m=JSON.parse(`{"title":"HN Post Draft — CQ: AI Agent's External Brain","description":"","frontmatter":{},"headers":[],"relativePath":"launch/hn-post.md","filePath":"launch/hn-post.md"}`),n={name:"launch/hn-post.md"};function i(s,e,l,d,c,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="hn-post-draft-—-cq-ai-agent-s-external-brain" tabindex="-1">HN Post Draft — CQ: AI Agent&#39;s External Brain <a class="header-anchor" href="#hn-post-draft-—-cq-ai-agent-s-external-brain" aria-label="Permalink to &quot;HN Post Draft — CQ: AI Agent&#39;s External Brain&quot;">​</a></h1><h2 id="title" tabindex="-1">Title <a class="header-anchor" href="#title" aria-label="Permalink to &quot;Title&quot;">​</a></h2><p><strong>Show HN: CQ – AI agent orchestration with persistent memory and verifiable experiments</strong></p><h2 id="body-1-paragraph" tabindex="-1">Body (1 paragraph) <a class="header-anchor" href="#body-1-paragraph" aria-label="Permalink to &quot;Body (1 paragraph)&quot;">​</a></h2><p>We&#39;ve been building CQ for the past year as the external brain for AI agents: every conversation across Claude Code, ChatGPT, Cursor, and Gemini accumulates into a searchable knowledge base, and every ML experiment links to a verifiable URL with metric, command, and git SHA. The core is a Go MCP server that runs locally (stdio) with a Python sidecar for document parsing and persona learning. Key pieces: a task orchestrator that spawns parallel Claude workers for large refactors, an end-to-end relay for NAT-traversed GPU workers, and a 3-layer wire validation system we built after shipping v1.60.0 with four silent wire bugs that passed 29 code reviews. Pro tier ($36/yr Early Bird, first 1,000 users) adds cross-project memory, cross-platform sync, and autonomous research loops on remote GPUs. Feedback welcome — especially on the Evidence Web URL scheme and the persona learning approach.</p><h2 id="release-notes-excerpt" tabindex="-1">Release Notes Excerpt <a class="header-anchor" href="#release-notes-excerpt" aria-label="Permalink to &quot;Release Notes Excerpt&quot;">​</a></h2><p><strong>v1.66.0 — Evidence Web</strong></p><ul><li><code>/exp/{id}</code>, <code>/compare?ids=a,b,c</code>, <code>/thread/{id}</code>, <code>/doc/{id}</code> — every agent claim is now a verifiable URL</li><li>Evidence Web deployed at evidence.pilab.kr</li><li>Polar checkout E2E with p95 latency measurement</li><li>SLO dashboard at <code>/internal/slo</code></li><li><code>cq intro</code> onboarding command</li><li>CompletionHook for journal lifecycle tracking</li></ul><h2 id="platform-notes" tabindex="-1">Platform Notes <a class="header-anchor" href="#platform-notes" aria-label="Permalink to &quot;Platform Notes&quot;">​</a></h2><ul><li>HN: use &quot;Show HN&quot; prefix, link to GitHub release v1.66.0</li><li>PH: screenshot of Evidence Web compare view + terminal demo GIF</li><li>Twitter/X: thread starting with the 3-line value prop from the landing page</li></ul>',10)])])}const u=a(n,[["render",i]]);export{m as __pageData,u as default};
